1	/**
2	 * TypeScript types for .yoke.yml configuration.
3	 *
4	 * Derived from docs/design/schemas/yoke-config.schema.json (JSON Schema draft-2020-12).
5	 * Version "1" is the only supported version.
6	 *
7	 * Two forms:
8	 *   RawConfig      — direct YAML parse output; path fields may be relative strings.
9	 *   ResolvedConfig — RawConfig with all path fields guaranteed to be absolute,
10	 *                    plus a `configDir` field. All downstream modules consume
11	 *                    ResolvedConfig only.
12	 *
13	 * Resolved at load time (relative → absolute, base = .yoke.yml directory):
14	 *   phases[*].prompt_template
15	 *   phases[*].cwd                          (if present)
16	 *   phases[*].output_artifacts[*].schema   (if present)
17	 *   worktrees.teardown.script              (if present)
18	 *
19	 * NOT resolved (runtime-relative to the worktree, unknown at load time):
20	 *   pipeline.stages[*].items_from
21	 *   phases[*].output_artifacts[*].path
22	 */
23	
24	// ---------------------------------------------------------------------------
25	// Action grammar (mirrors docs/design/schemas/pre-post-action-grammar.md)
26	// ---------------------------------------------------------------------------
27	
28	export type RetryMode =
29	  | 'continue'
30	  | 'fresh_with_failure_summary'
31	  | 'fresh_with_diff'
32	  | 'awaiting_user';
33	
34	export type ActionValue =
35	  | 'continue'
36	  | 'stop-and-ask'
37	  | 'stop'
38	  | { goto: string; max_revisits?: number }
39	  | { retry: { mode: 'continue' | 'fresh_with_failure_summary' | 'fresh_with_diff'; max: number } }
40	  | { fail: { reason: string } };
41	
42	/** Keys are exit-code strings ("0"–"255") or the wildcard "*". */
43	export type ActionsMap = Record<string, ActionValue>;
44	
45	// ---------------------------------------------------------------------------
46	// Pre / post commands
47	// ---------------------------------------------------------------------------
48	
49	export interface PrePostCommand {
50	  name: string;
51	  /** argv-form; spawned with shell: false */
52	  run: string[];
53	  timeout_s?: number;
54	  env?: Record<string, string>;
55	  actions: ActionsMap;
56	}
57	
58	// ---------------------------------------------------------------------------
59	// Phase
60	// ---------------------------------------------------------------------------
61	
62	export interface OutputArtifact {
63	  /** Relative to worktree (not resolved at load time). */
64	  path: string;
65	  /** Path to a JSON Schema file. Absolute in ResolvedConfig. */
66	  schema?: string;
67	  required?: boolean;
68	}
69	
70	export interface Heartbeat {
71	  /**
72	   * Interval in seconds for the liveness probe (kill(pid, 0)).
73	   * Default: 30 s.
74	   */
75	  liveness_interval_s?: number;
76	  /** Seconds of stdout silence before the stream-activity watchdog warns. Default: 90 s. */
77	  activity_timeout_s?: number;
78	  /** Tool-name → wall-clock budget in seconds. */
79	  per_tool_budgets?: Record<string, number>;
80	}
81	
82	export interface Phase {
83	  command: string;
84	  args: string[];
85	  env?: Record<string, string>;
86	  /** Absolute in ResolvedConfig (if present). */
87	  cwd?: string;
88	  /** Absolute in ResolvedConfig. */
89	  prompt_template: string;
90	  output_artifacts?: OutputArtifact[];
91	  max_outer_retries?: number;
92	  retry_ladder?: RetryMode[];
93	  heartbeat?: Heartbeat;
94	  pre?: PrePostCommand[];
95	  post?: PrePostCommand[];
96	}
97	
98	// ---------------------------------------------------------------------------
99	// Pipeline / stages
100	// ---------------------------------------------------------------------------
101	
102	export interface ItemsDisplay {
103	  title?: string;
104	  subtitle?: string;
105	}
106	
107	export interface Stage {
108	  id: string;
109	  run: 'once' | 'per-item';
110	  /** Ordered phase keys referencing the top-level phases map. */
111	  phases: string[];
112	  needs_approval?: boolean;
113	  /** Relative to worktree — NOT resolved at load time. */
114	  items_from?: string;
115	  items_list?: string;
116	  items_id?: string;
117	  items_depends_on?: string;
118	  items_display?: ItemsDisplay;
119	}
120	
121	export interface Pipeline {
122	  stages: Stage[];
123	}
124	
125	// ---------------------------------------------------------------------------
126	// Top-level optional sections
127	// ---------------------------------------------------------------------------
128	
129	export interface Project {
130	  name: string;
131	}
132	
133	export interface WorktreesBootstrap {
134	  commands?: string[];
135	}
136	
137	export interface WorktreesTeardown {
138	  /** Absolute in ResolvedConfig (if present). */
139	  script?: string;
140	}
141	
142	export interface Worktrees {
143	  base_dir?: string;
144	  branch_prefix?: string;
145	  auto_cleanup?: boolean;
146	  cleanup_tool?: 'git' | 'lazyworktree' | 'custom';
147	  bootstrap?: WorktreesBootstrap;
148	  teardown?: WorktreesTeardown;
149	}
150	
151	export interface NotificationMechanism {
152	  type: 'browser_push' | 'macos_native';
153	}
154	
155	export interface Notifications {
156	  enabled?: boolean;
157	  severity_map?: Record<string, string>;
158	  mechanisms?: NotificationMechanism[];
159	}
160	
161	export interface Github {
162	  enabled?: boolean;
163	  auto_pr?: boolean;
164	  pr_target_branch?: string;
165	  auth_order?: Array<'env:GITHUB_TOKEN' | 'gh:auth:token'>;
166	  attach_artifacts_to_pr?: boolean;
167	  link_issues?: boolean;
168	}
169	
170	export type SqliteRetention = 'forever' | { max_age_days: number };
171	
172	export interface RetentionStreamJsonLogs {
173	  max_age_days?: number;
174	  max_total_bytes?: number;
175	}
176	
177	export interface Retention {
178	  sqlite?: SqliteRetention;
179	  stream_json_logs?: RetentionStreamJsonLogs;
180	  worktrees?: 'workflow-completion' | 'manual' | 'on-disk-pressure';
181	}
182	
183	export interface Logging {
184	  retain_stream_json?: boolean;
185	}
186	
187	export interface Runtime {
188	  keep_awake?: boolean;
189	}
190	
191	export interface RateLimit {
192	  handling?: 'passive';
193	  /** v1.1 only; rejected at load time in v1 by the schema. */
194	  usage_pause_threshold?: number;
195	}
196	
197	export interface Ui {
198	  port?: number;
199	  bind?: '127.0.0.1';
200	  auth?: false;
201	}
202	
203	// ---------------------------------------------------------------------------
204	// Root config types
205	// ---------------------------------------------------------------------------
206	
207	/**
208	 * Raw config as parsed from .yoke.yml — before path resolution.
209	 * Relative path fields are still relative strings in this type.
210	 */
211	export interface RawConfig {
212	  version: string;
213	  project: Project;
214	  pipeline: Pipeline;
215	  /** Keys are phase names referenced by pipeline stages. */
216	  phases: Record<string, Phase>;
217	  worktrees?: Worktrees;
218	  notifications?: Notifications;
219	  github?: Github;
220	  retention?: Retention;
221	  logging?: Logging;
222	  runtime?: Runtime;
223	  rate_limit?: RateLimit;
224	  ui?: Ui;
225	  safety_mode?: 'strict' | 'default' | 'yolo';
226	}
227	
228	/**
229	 * Config with all relative paths resolved to absolute paths, using the
230	 * .yoke.yml directory as the base. All downstream modules consume only
231	 * this type — never RawConfig.
232	 */
233	export type ResolvedConfig = RawConfig & {
234	  /** Absolute path of the directory containing .yoke.yml. */
235	  configDir: string;
236	};
