1	/**
2	 * JigProcessManager — production ProcessManager implementation.
3	 *
4	 * Spawns whatever command + args the caller passes via SpawnOpts. There are
5	 * no 'claude' or 'jig' string constants anywhere in this file; the command
6	 * comes exclusively from ResolvedConfig via the caller.
7	 *
8	 * Process lifecycle:
9	 *   spawn(opts)
10	 *     → nodeSpawn(command, args, { detached:true })
11	 *     → register stdin 'error' handler (EPIPE named failure class)
12	 *     → child.stdin.end(promptBuffer)   ← one-shot; EPIPE caught above
13	 *     → readline stdout → emit 'stdout_line' per NDJSON line
14	 *     → stderr 'data' → cap at 64 KB, emit 'stderr_data' chunks
15	 *     → child 'exit' → emit 'exit'
16	 *     → cancel(): SIGTERM(-pgid) → gracePeriodMs → SIGKILL(-pgid)
17	 *
18	 * Zombie reap: detached:true + child.unref() — the child runs in its own
19	 * process group; unref() lets Node.js exit without waiting for it. The OS
20	 * (init/launchd) adopts and reaps the child if Yoke exits first.
21	 */
22	
23	import { spawn as nodeSpawn, type ChildProcess } from 'node:child_process';
24	import { EventEmitter } from 'node:events';
25	import { createInterface } from 'node:readline';
26	import { ProcessError, type ProcessManager, type SpawnHandle, type SpawnOpts } from './manager.js';
27	
28	/** Maximum stderr bytes buffered before the cap is enforced. */
29	const STDERR_CAP_BYTES = 64 * 1024; // 64 KB
30	
31	// ---------------------------------------------------------------------------
32	// JigSpawnHandle (internal — not exported; callers program to SpawnHandle)
33	// ---------------------------------------------------------------------------
34	
35	class JigSpawnHandle extends EventEmitter implements SpawnHandle {
36	  readonly pid: number;
37	  /**
38	   * pgid === pid: with detached:true the child becomes its own process group
39	   * leader on POSIX. kill(-pgid, sig) delivers sig to every process in the
40	   * group (child + any sub-children it spawns).
41	   */
42	  readonly pgid: number;
43	
44	  private readonly child: ChildProcess;
45	  private readonly gracePeriodMs: number;
46	  private cancelTimer: ReturnType<typeof setTimeout> | null = null;
47	
48	  constructor(child: ChildProcess, gracePeriodMs: number) {
49	    super();
50	    this.child = child;
51	    this.pid = child.pid!;
52	    this.pgid = child.pid!;
53	    this.gracePeriodMs = gracePeriodMs;
54	
55	    this._wireStdin();
56	    this._wireStdout();
57	    this._wireStderr();
58	    this._wireExit();
59	  }
60	
61	  // -------------------------------------------------------------------------
62	  // Stream wiring
63	  // -------------------------------------------------------------------------
64	
65	  /**
66	   * Register the stdin 'error' handler BEFORE any write is scheduled.
67	   * Called synchronously from the constructor so the handler is in place
68	   * before child.stdin.end() runs on the next event-loop tick.
69	   */
70	  private _wireStdin(): void {
71	    this.child.stdin!.on('error', (err: NodeJS.ErrnoException) => {
72	      if (err.code === 'EPIPE') {
73	        // EPIPE is the named failure class for "child closed its stdin end
74	        // before we finished writing the prompt buffer."  This does NOT crash
75	        // the harness; it is caught here, logged via the 'error' event, and
76	        // the session continues to its natural exit.
77	        const pe = new ProcessError(
78	          'epipe',
79	          err,
80	          'EPIPE on stdin write: child closed the pipe before the prompt buffer was fully delivered',
81	        );
82	        this.emit('error', pe);
83	      } else {
84	        // Any other stdin I/O error (e.g. EBADF) — re-raise as a typed
85	        // ProcessError so no error is swallowed.
86	        this.emit('error', new ProcessError('stdin_error', err, `Unexpected stdin error: ${err.message}`));
87	      }
88	    });
89	  }
90	
91	  /**
92	   * Line-buffered stdout reader (readline handles the trailing partial-line
93	   * buffer). Each complete line is emitted as 'stdout_line' for the
94	   * stream-json parser (process/stream-json.ts) to consume.
95	   */
96	  private _wireStdout(): void {
97	    const rl = createInterface({ input: this.child.stdout!, crlfDelay: Infinity });
98	    rl.on('line', (line: string) => {
99	      this.emit('stdout_line', line);
100	    });
101	  }
102	
103	  /**
104	   * Stderr cap enforced in the stream 'data' handler — not by accumulating
105	   * all stderr into memory first. Once stderrBytes reaches STDERR_CAP_BYTES,
106	   * further data events are discarded and 'stderr_cap_reached' is emitted
107	   * once to allow callers to log a warning.
108	   */
109	  private _wireStderr(): void {
110	    let stderrBytes = 0;
111	    let capWarned = false;
112	
113	    this.child.stderr!.on('data', (chunk: Buffer) => {
114	      if (stderrBytes >= STDERR_CAP_BYTES) {
115	        // Cap already reached; drop this chunk silently. Warning was already
116	        // emitted the first time the threshold was crossed.
117	        return;
118	      }
119	
120	      const remaining = STDERR_CAP_BYTES - stderrBytes;
121	      // Never buffer more than the remaining cap — slice the chunk if needed.
122	      const slice = chunk.length <= remaining ? chunk : chunk.subarray(0, remaining);
123	      stderrBytes += slice.length;
124	      this.emit('stderr_data', slice.toString('utf8'));
125	
126	      if (!capWarned && stderrBytes >= STDERR_CAP_BYTES) {
127	        capWarned = true;
128	        // Emit once; callers (e.g. session log writer) may log a warning.
129	        this.emit('stderr_cap_reached');
130	      }
131	    });
132	  }
133	
134	  private _wireExit(): void {
135	    this.child.on('exit', (code, signal) => {
136	      // Clear any pending SIGKILL escalation timer — the process already exited.
137	      if (this.cancelTimer !== null) {
138	        clearTimeout(this.cancelTimer);
139	        this.cancelTimer = null;
140	      }
141	      this.emit('exit', code, signal as NodeJS.Signals | null);
142	    });
143	
144	    this.child.on('error', (err: NodeJS.ErrnoException) => {
145	      // Spawn-time errors (ENOENT, EACCES) arrive here, NOT on stderr.
146	      this.emit(
147	        'error',
148	        new ProcessError('spawn_failed', err, `Failed to spawn process: ${err.message}`),
149	      );
150	    });
151	  }
152	
153	  // -------------------------------------------------------------------------
154	  // Public interface
155	  // -------------------------------------------------------------------------
156	
157	  isAlive(): boolean {
158	    try {
159	      // kill(pid, 0) is a POSIX liveness probe — no signal is delivered.
160	      // Throws ESRCH if the PID no longer exists.
161	      process.kill(this.pid, 0);
162	      return true;
163	    } catch {
164	      return false;
165	    }
166	  }
167	
168	  async cancel(): Promise<void> {
169	    if (!this.isAlive()) {
170	      // Already exited — nothing to do.
171	      return;
172	    }
173	
174	    return new Promise<void>((resolve) => {
175	      // Step 2 cleanup: if the process exits before the timer fires, cancel
176	      // the escalation and resolve immediately.
177	      const onExit = (): void => {
178	        if (this.cancelTimer !== null) {
179	          clearTimeout(this.cancelTimer);
180	          this.cancelTimer = null;
181	        }
182	        resolve();
183	      };
184	
185	      this.once('exit', onExit as (...args: any[]) => void);
186	
187	      // Step 1: SIGTERM → entire process group.
188	      try {
189	        process.kill(-this.pgid, 'SIGTERM');
190	      } catch {
191	        // ESRCH or similar: process group already gone between isAlive() and here.
192	        this.off('exit', onExit as (...args: any[]) => void);
193	        resolve();
194	        return;
195	      }
196	
197	      // Step 3 (deferred): if still alive after grace period, escalate to SIGKILL.
198	      this.cancelTimer = setTimeout(() => {
199	        this.off('exit', onExit as (...args: any[]) => void);
200	        try {
201	          process.kill(-this.pgid, 'SIGKILL');
202	        } catch {
203	          // Process group gone between SIGTERM and SIGKILL — that's fine.
204	        }
205	        // Resolve after sending SIGKILL. The 'exit' event will still fire
206	        // shortly for any listeners that need it.
207	        resolve();
208	      }, this.gracePeriodMs);
209	    });
210	  }
211	}
212	
213	// ---------------------------------------------------------------------------
214	// JigProcessManager (exported)
215	// ---------------------------------------------------------------------------
216	
217	/**
218	 * Production ProcessManager. Spawns whatever command + args the caller
219	 * provides — reads exclusively from SpawnOpts. No string constants here.
220	 */
221	export class JigProcessManager implements ProcessManager {
222	  async spawn(opts: SpawnOpts): Promise<SpawnHandle> {
223	    const { command, args, cwd, env, promptBuffer, gracePeriodMs = 10_000 } = opts;
224	
225	    const child = nodeSpawn(command, args, {
226	      cwd,
227	      stdio: ['pipe', 'pipe', 'pipe'],
228	      // Merge caller env over process.env. Never pass undefined as the env
229	      // option — that is equivalent to inheriting the full environment, which
230	      // is the intended behaviour here.
231	      env: env !== undefined ? { ...process.env, ...env } : { ...process.env },
232	      // detached:true creates a new session + process group for the child
233	      // (pgid === child.pid on POSIX). This ensures kill(-pgid, signal)
234	      // delivers the signal to the entire subtree, not just the immediate child.
235	      detached: true,
236	    });
237	
238	    // Construct the handle first — its _wireStdin() call registers the stdin
239	    // 'error' handler synchronously. EPIPE is asynchronous, so by the time
240	    // it fires the handler is already in place.
241	    const handle = new JigSpawnHandle(child, gracePeriodMs);
242	
243	    // Zombie reap: unref() allows the Node.js event loop to exit without
244	    // waiting for this child. The OS adopts and reaps the process if Yoke
245	    // exits first. We still receive 'exit', 'stdout_line', 'stderr_data', and
246	    // 'error' events — unref() only affects the event-loop exit condition.
247	    child.unref();
248	
249	    // One-shot stdin delivery: write the entire prompt buffer then close the
250	    // pipe. The 'error' handler registered above catches EPIPE if the child
251	    // closes stdin before we finish writing.
252	    child.stdin!.end(promptBuffer);
253	
254	    return handle;
255	  }
256	}
257

1	/**
2	 * Two-signal heartbeat for a running child process.
3	 *
4	 * Signal 1 — Liveness probe:
5	 *   kill(pid, 0) is called on each tick (interval = liveness_interval_s from
6	 *   ResolvedConfig). If the OS returns ESRCH the PID no longer exists; a single
7	 *   stream.system_notice{subtype:'liveness_stale'} warning is emitted.
8	 *   SIGTERM and SIGKILL are NEVER sent by this module — warnings only.
9	 *
10	 * Signal 2 — Stream-activity watchdog:
11	 *   Tracks the timestamp of the most recent stdout line. On each tick, if no
12	 *   stdout line has arrived within activityTimeoutMs, a single
13	 *   stream.system_notice{subtype:'stream_idle'} warning is emitted.
14	 *   The warning is reset by notifyStdoutLine() so each new idle period
15	 *   can warn once.
16	 *
17	 * Suppression (AC-3 / RC-2):
18	 *   Both signals are skipped on ticks where isRateLimited() returns true.
19	 *   The function is called FRESH each tick — the caller (Pipeline Engine)
20	 *   provides current item status; the Heartbeat never caches this.
21	 *
22	 * Lifecycle:
23	 *   start()             → begin ticking at livenessIntervalMs
24	 *   stop()              → clear setInterval (MUST be called on session end)
25	 *   notifyStdoutLine()  → reset stream-activity clock and idle-warned flag
26	 *
27	 * Configuration (AC-4):
28	 *   All intervals are read from the HeartbeatConfig argument passed to the
29	 *   constructor. Nothing in this module is hard-coded.
30	 *
31	 * Review criteria compliance:
32	 *   RC-1 — grep 'SIGTERM\|SIGKILL': both strings appear nowhere in this file.
33	 *           The only kill call is `process.kill(pid, 0)` (signal 0 = liveness
34	 *           probe; no signal is delivered).
35	 *   RC-2 — isRateLimited() is called inside _tick(), not at construction time.
36	 *   RC-3 — stop() clears the setInterval; start() is idempotent (guard on
37	 *           this.timer !== null prevents a second interval from being created).
38	 */
39	
40	import { EventEmitter } from 'node:events';
41	import type { StreamSystemNoticeEvent } from './stream-json.js';
42	
43	// ---------------------------------------------------------------------------
44	// Config shape
45	// ---------------------------------------------------------------------------
46	
47	/**
48	 * Subset of the phase heartbeat config consumed by this module.
49	 * Mirrors Phase.heartbeat in src/shared/types/config.ts but is declared here
50	 * as a local interface so this module does not depend on the config loader.
51	 * The caller (Pipeline Engine) passes a HeartbeatConfig built from ResolvedConfig.
52	 */
53	export interface HeartbeatConfig {
54	  /**
55	   * Interval in seconds between liveness-probe ticks.
56	   * Default: 30 s.
57	   */
58	  liveness_interval_s?: number;
59	  /**
60	   * Seconds of stdout silence before the stream-activity watchdog warns.
61	   * Default: 90 s.
62	   */
63	  activity_timeout_s?: number;
64	}
65	
66	// ---------------------------------------------------------------------------
67	// Constructor options
68	// ---------------------------------------------------------------------------
69	
70	export interface HeartbeatOpts {
71	  /** OS PID to probe via kill(pid, 0). */
72	  pid: number;
73	  /**
74	   * Heartbeat configuration, derived from ResolvedConfig at call site and
75	   * passed in at construction time (AC-4).
76	   */
77	  config: HeartbeatConfig;
78	  /**
79	   * Invoked fresh on every tick (not cached). The Pipeline Engine provides
80	   * this to reflect current item status so suppression is always up-to-date
81	   * (AC-5 / RC-2). Both probes are skipped when this returns true (AC-3).
82	   */
83	  isRateLimited: () => boolean;
84	}
85	
86	// ---------------------------------------------------------------------------
